#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=10005;
int n,m,k,dfn[N],low[N],vis[N],siz[N],id[N],cnt,cnt2;
stack<int> st;
vector<int> g[N];
void tarjan(int u)
{
	low[u]=dfn[u]=++cnt;
	st.push(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(!dfn[v])
		{
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
	{
		cnt2++;
		int v;
		while(v=st.top())
		{
			vis[v]=0;
			id[v]=cnt2;
			siz[cnt2]++;
			st.pop();
			if(v==u) break;
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>k;
	while(k--)
	{
		cin>>n>>m;
		for(int i=1;i<=m;i++)
		{
			string u,v;
			cin>>u>>v;
			int uu=0,vv=0;
			for(int j=1;j<u.size();j++) uu=uu*10+(u[j]-'0');
			for(int j=1;j<v.size();j++) vv=vv*10+(v[j]-'0');
			uu=uu*2-1+(u[0]=='m');
			vv=vv*2-1+(v[0]=='m');
			g[uu].push_back((vv%2==0)?(vv-1):(vv+1));
			g[vv].push_back((uu%2==0)?(uu-1):(uu+1));
		}
		for(int i=1;i<=2*n;i++)
		{
			if(!dfn[i])
			{
				tarjan(i);	
			}
		}
		for(int i=1;i<=2*n;i+=2)
		{
			if(id[i]==id[i+1])
			{
				cout<<"BAD\n";
				goto end;
			}	
		}
		cout<<"GOOD\n";
		end: ;
		for(int i=1;i<=2*n;i++)
		{
			g[i].clear();
			dfn[i]=low[i]=id[i]=siz[i]=vis[i]=0;
		}
		cnt=cnt2=0;
	}
	return 0;
}
